import { useNavigate } from "react-router-dom";
import { useState } from 'react';
import { post, get } from "../servicos/api";

function PaginaReceitaCadastro() {
    const navegador = useNavigate();

    const [prontuario_id, setProntuarioId] = useState('');
    const [paciente_id, setPacienteId] = useState('');
    const [profissional, setProfissional] = useState('');
    const [crm, setCrm] = useState('');
    const [orientacoes, setOrientacoes] = useState('');
    const [itens, setItens] = useState([{ medicamento: '', dosagem: '', posologia: '', quantidade: 1 }]);

    // Integração G5
    const [registros, setRegistros] = useState([]);
    const [buscando, setBuscando] = useState(false);
    const [prontuarioEncontrado, setProntuarioEncontrado] = useState(false);

    const voltar = () => {
        navegador('/');
    }

    // Buscar prontuário e registros clínicos do G5
    const buscarNoG5 = async () => {
        if (!paciente_id) {
            alert('Informe o ID do paciente primeiro.');
            return;
        }

        setBuscando(true);
        setRegistros([]);
        setProntuarioEncontrado(false);
        setProntuarioId('');

        try {
            const resposta = await get('g5/registros/' + paciente_id);

            // A resposta pode ser um objeto ou array
            let dados = resposta;
            if (!Array.isArray(dados)) {
                dados = [dados];
            }

            if (dados.length > 0) {
                // Pega o prontuario_id do primeiro resultado
                const pId = dados[0].prontuario_id || dados[0].id;
                setProntuarioId(pId);
                setRegistros(dados);
                setProntuarioEncontrado(true);
            }
        } catch (error) {
            alert('Prontuário não encontrado no G5 para este paciente.');
        } finally {
            setBuscando(false);
        }
    }

    const adicionarItem = () => {
        setItens([...itens, { medicamento: '', dosagem: '', posologia: '', quantidade: 1 }]);
    }

    const removerItem = (indice) => {
        if (itens.length === 1) {
            alert('A receita deve ter ao menos 1 medicamento.');
            return;
        }
        setItens(itens.filter((item, i) => i !== indice));
    }

    const atualizarItem = (indice, campo, valor) => {
        const novosItens = itens.map((item, i) => {
            if (i === indice) {
                return { ...item, [campo]: valor };
            }
            return item;
        });
        setItens(novosItens);
    }

    const salvar = async () => {
        const objeto = {
            "prontuario_id": prontuario_id,
            "paciente_id": paciente_id,
            "profissional": profissional,
            "crm": crm,
            "orientacoes": orientacoes,
            "itens": itens.map(item => ({
                ...item,
                quantidade: Number(item.quantidade)
            }))
        }

        try {
            const resposta = await post('receita', objeto);
            alert('Receita emitida com sucesso!');
            navegador('/receita/' + resposta.idreceita);
        } catch (error) {
            if (error.response && error.response.data && error.response.data.mensagem) {
                alert(error.response.data.mensagem);
            } else {
                console.log('Erro ao inserir: ' + error);
            }
        }
    }

    return (
        <div className="container my-5">
            <div className="row justify-content-center">
                <div className="col-lg-8">
                    <div className="card shadow border-0">
                        <div className="card-header bg-success text-white py-3">
                            <h5 className="mb-0">Emitir Nova Receita</h5>
                        </div>
                        <div className="card-body p-4">
                            <>
                                <p className="text-muted mb-4">
                                    A receita será validada contra o registro clínico do Prontuário (G5). Após emitida, não poderá ser alterada.
                                </p>

                                {/* ===== BUSCA NO G5 ===== */}
                                <div className="card bg-light border-success mb-4">
                                    <div className="card-header bg-success bg-opacity-10">
                                        <h6 className="mb-0 text-success">
                                            <i className="bi bi-search me-1" />
                                            Buscar Prontuário no G5
                                        </h6>
                                    </div>
                                    <div className="card-body">
                                        <div className="row align-items-end">
                                            <div className="col-md-6 mb-2">
                                                <label className="form-label fw-bold">ID do Paciente</label>
                                                <input
                                                    type="number"
                                                    className="form-control"
                                                    placeholder="Ex: 15"
                                                    onChange={(e) => { setPacienteId(e.target.value); setProntuarioEncontrado(false); setRegistros([]); }}
                                                    value={paciente_id}
                                                />
                                            </div>
                                            <div className="col-md-6 mb-2">
                                                <button
                                                    className="btn btn-success w-100"
                                                    onClick={buscarNoG5}
                                                    disabled={buscando}
                                                >
                                                    {buscando ? 'Buscando...' : 'Buscar Prontuário (G5)'}
                                                </button>
                                            </div>
                                        </div>

                                        {prontuarioEncontrado && (
                                            <div className="alert alert-success mt-3 mb-0">
                                                <i className="bi bi-check-circle me-1" />
                                                Prontuário <strong>#{prontuario_id}</strong> encontrado no G5 para o paciente #{paciente_id}
                                            </div>
                                        )}
                                    </div>
                                </div>

                                {/* ===== REGISTROS CLÍNICOS DO G5 ===== */}
                                {registros.length > 0 && (
                                    <div className="card border-info mb-4">
                                        <div className="card-header bg-info bg-opacity-10">
                                            <h6 className="mb-0 text-info">
                                                <i className="bi bi-file-earmark-medical me-1" />
                                                Registros Clínicos do Paciente (G5)
                                            </h6>
                                        </div>
                                        <div className="card-body p-0">
                                            <table className="table table-sm table-hover mb-0">
                                                <thead className="table-light">
                                                    <tr>
                                                        <th>ID</th>
                                                        <th>Tipo</th>
                                                        <th>Diagnóstico</th>
                                                        <th>Sintomas</th>
                                                        <th>Data</th>
                                                    </tr>
                                                </thead>
                                                <tbody>
                                                    {registros.map((r, i) => (
                                                        <tr key={i}>
                                                            <td>{r.id}</td>
                                                            <td><span className="badge bg-info">{r.tipo_registro || r.tipo_registro_id || '-'}</span></td>
                                                            <td>{r.diagnostico ? r.diagnostico.substring(0, 60) + '...' : '-'}</td>
                                                            <td>{r.sintomas ? r.sintomas.substring(0, 60) + '...' : '-'}</td>
                                                            <td>{r.data_registro || '-'}</td>
                                                        </tr>
                                                    ))}
                                                </tbody>
                                            </table>
                                        </div>
                                    </div>
                                )}

                                {/* ===== DADOS DA RECEITA ===== */}
                                <div className="row">
                                    <div className="col-md-6 mb-3">
                                        <label className="form-label fw-bold">ID do Prontuário (G5)</label>
                                        <input
                                            type="number"
                                            className="form-control"
                                            required=""
                                            placeholder="Preenchido automaticamente"
                                            onChange={(e) => setProntuarioId(e.target.value)}
                                            value={prontuario_id}
                                            readOnly={prontuarioEncontrado}
                                        />
                                        {prontuarioEncontrado && (
                                            <small className="text-success">Preenchido automaticamente pelo G5</small>
                                        )}
                                    </div>
                                    <div className="col-md-6 mb-3">
                                        <label className="form-label fw-bold">ID do Paciente</label>
                                        <input
                                            type="number"
                                            className="form-control"
                                            required=""
                                            value={paciente_id}
                                            readOnly
                                        />
                                    </div>
                                </div>

                                <div className="row">
                                    <div className="col-md-6 mb-3">
                                        <label className="form-label fw-bold">Profissional</label>
                                        <input
                                            type="text"
                                            className="form-control"
                                            required=""
                                            placeholder="Dra. Ana Souza"
                                            onChange={(e) => setProfissional(e.target.value)}
                                            value={profissional}
                                        />
                                    </div>
                                    <div className="col-md-6 mb-3">
                                        <label className="form-label fw-bold">CRM</label>
                                        <input
                                            type="text"
                                            className="form-control"
                                            required=""
                                            placeholder="SC-12345"
                                            onChange={(e) => setCrm(e.target.value)}
                                            value={crm}
                                        />
                                    </div>
                                </div>

                                <hr />
                                <h6 className="fw-bold mb-3">
                                    <i className="bi bi-capsule me-1" />
                                    Medicamentos
                                </h6>

                                {itens.map((item, i) => (
                                    <div key={i} className="card bg-light mb-3">
                                        <div className="card-body">
                                            <div className="d-flex justify-content-between align-items-center mb-2">
                                                <strong>Medicamento #{i + 1}</strong>
                                                <button
                                                    className="btn btn-sm btn-outline-danger"
                                                    onClick={() => removerItem(i)}
                                                >
                                                    <i className="bi bi-trash" /> Remover
                                                </button>
                                            </div>
                                            <div className="row">
                                                <div className="col-md-6 mb-2">
                                                    <label className="form-label">Medicamento</label>
                                                    <input
                                                        type="text"
                                                        className="form-control"
                                                        placeholder="Amoxicilina"
                                                        onChange={(e) => atualizarItem(i, 'medicamento', e.target.value)}
                                                        value={item.medicamento}
                                                    />
                                                </div>
                                                <div className="col-md-6 mb-2">
                                                    <label className="form-label">Dosagem</label>
                                                    <input
                                                        type="text"
                                                        className="form-control"
                                                        placeholder="500mg"
                                                        onChange={(e) => atualizarItem(i, 'dosagem', e.target.value)}
                                                        value={item.dosagem}
                                                    />
                                                </div>
                                            </div>
                                            <div className="row">
                                                <div className="col-md-8 mb-2">
                                                    <label className="form-label">Posologia</label>
                                                    <input
                                                        type="text"
                                                        className="form-control"
                                                        placeholder="1 cápsula a cada 8h por 7 dias"
                                                        onChange={(e) => atualizarItem(i, 'posologia', e.target.value)}
                                                        value={item.posologia}
                                                    />
                                                </div>
                                                <div className="col-md-4 mb-2">
                                                    <label className="form-label">Quantidade</label>
                                                    <input
                                                        type="number"
                                                        className="form-control"
                                                        min="1"
                                                        onChange={(e) => atualizarItem(i, 'quantidade', e.target.value)}
                                                        value={item.quantidade}
                                                    />
                                                </div>
                                            </div>
                                        </div>
                                    </div>
                                ))}

                                <button className="btn btn-outline-success mb-3" onClick={adicionarItem}>
                                    <i className="bi bi-plus-circle me-1" />
                                    Adicionar Medicamento
                                </button>

                                <hr />

                                <div className="mb-3">
                                    <label className="form-label fw-bold">Orientações Gerais (opcional)</label>
                                    <textarea
                                        className="form-control"
                                        rows="3"
                                        placeholder="Tomar com alimentos, evitar álcool..."
                                        onChange={(e) => setOrientacoes(e.target.value)}
                                        value={orientacoes}
                                    />
                                </div>

                                <hr />
                                <div className="d-flex justify-content-between">
                                    <a onClick={(e) => voltar()} className="btn btn-link text-muted">
                                        Voltar para a lista
                                    </a>
                                    <button onClick={(e) => salvar()} className="btn btn-success px-5">
                                        Emitir Receita
                                    </button>
                                </div>
                            </>
                        </div>
                    </div>
                </div>
            </div>
        </div>
    );
}

export default PaginaReceitaCadastro;
